.status-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
}

.timestamp {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-dim);
}

.scope-badge {
  padding: 3px 10px;
  border-radius: 999px;
  border: 1px solid var(--border);
  font-size: 11px;
  color: var(--text-muted);
  font-weight: 600;
}

/* --- Metrics Grid --- */
.metrics-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  padding: 22px 24px;
}

.metric-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-top: 3px solid;
  border-radius: var(--radius-lg);
  padding: 20px;
  box-shadow: var(--shadow-card);
  transition: box-shadow var(--transition);
}

.metric-card:hover {
  box-shadow: var(--shadow-hover);
}

.metric-icon {
  width: 38px;
  height: 38px;
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  margin-bottom: 12px;
}

.metric-label {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  font-weight: 700;
  color: var(--text-muted);
  margin-bottom: 4px;
}

.metric-value {
  font-size: 30px;
  font-weight: 800;
  color: var(--text-bright);
  letter-spacing: -0.03em;
  font-variant-numeric: tabular-nums;
}

.metric-trend {
  font-size: 11px;
  font-weight: 600;
  margin-top: 4px;
}

